var raw = parseInt(value.replace('0x',''), 16);
if (isNaN(raw) || raw === 0) return 'OK';
var now = [];
if (raw & 0x1) now.push('under-voltage');
if (raw & 0x2) now.push('ARM freq capped');
if (raw & 0x4) now.push('throttled');
if (raw & 0x8) now.push('soft temp limit');
var past = [];
if (raw & 0x10000) past.push('under-voltage');
if (raw & 0x20000) past.push('ARM freq capped');
if (raw & 0x40000) past.push('throttled');
if (raw & 0x80000) past.push('soft temp limit');
var parts = [];
if (now.length) parts.push('NOW: ' + now.join(', '));
if (past.length) parts.push('SINCE BOOT: ' + past.join(', '));
return parts.join(' | ');
